-- Kamp-Update April 2026: farm_camps komplett auf die 42 Weidekamps (41 + Kiesdammkamp Süd) setzen.
-- Geometrie aus KML (Okt.25-Basis), Tippfehler/Kraale/Posten/Grenz-Polygone entfernt.
begin;
delete from farm_camps;
-- verwaiste Test-Bewegungen mit alten Kamp-Namen entfernen
delete from herd_movements where (from_camp is not null and from_camp not in (select name from farm_camps)) or (to_camp is not null and to_camp not in (select name from farm_camps));
commit;
